var smallestNumber = function(n, t) {
    let candidate = n;
    while (true) {
        let product = 1;
        let x = candidate;
        while (x > 0) {
            product *= x % 10;
            x = Math.floor(x / 10);
        }
        if (product % t === 0) return candidate;
        candidate += 1;
    }
};
